 const _20250615Ipados26 = "{\"parsed\":{\"_path\":\"/fr/20250615-ipados26\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"iPadOS 26 : L'iPad redevient (enfin) utile\",\"description\":\"Avec l'arrivée des fenêtres flottantes, iPadOS 18 transforme enfin l'iPad en outil productif digne de ce nom. Fini les limitations du Split View : on peut désormais jongler entre plusieurs apps comme sur un ordinateur classique.\",\"image\":\"/images/articles/ipad-mini-6.jpg\",\"createdAt\":\"2025-06-15\",\"id\":\"2025-06-15T00:00:00.000Z\",\"keywords\":\"iPadOS 18, Apple, iPad mini 6, productivité, fenêtres flottantes, Liquid Glass, Apple Intelligence\",\"summary\":\"iPadOS 18 introduit une vraie gestion des fenêtres, rendant l'iPad plus polyvalent. Un changement discret, mais fondamental pour ceux qui attendaient depuis des années un multitâche sérieux sur tablette.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"iPadOS 26 : L'iPad redevient (enfin) utile\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mon iPad Mini prenait la poussière depuis un moment. Il me servait pour deux usages : prendre des notes manuscrites en réunion (avec un stylet Bluetooth Ugreen, suffisant pour éviter l'achat d'un Apple Pencil hors de prix) et regarder quelques séries.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est tout.  J'avais tenté d'en faire une machine de travail d'appoint, mais l'expérience était frustrante. Impossible, par exemple, de suivre une vidéo YouTube tout en prenant des notes sérieusement. Le multitâche façon \\\"Split View\\\" est rigide, limitant, et loin de ce que propose un environnement de bureau classique.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"puis-est-arrivé-ipados-19-ou-pluttôt-26\"},\"children\":[{\"type\":\"text\",\"value\":\"Puis est arrivé iPadOS 19, ou pluttôt 26.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On peut passer sur les effets de transparence de \\\"Liquid Glass\\\" ou sur la promesse d'une IA omniprésente (Apple Intelligence). Le vrai changement, \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"c'est l'arrivée des fenêtres flottantes\"}]},{\"type\":\"text\",\"value\":\".\\nOui, des vraies fenêtres.\\nRedimensionnables, déplaçables, avec une vraie gestion de l'espace de travail. Pour la première fois, on peut travailler sur plusieurs applications à la fois, sans avoir l'impression de devoir faire des compromis.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"... (contenu abrégé pour commodité)\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"puis-est-arrivé-ipados-19-ou-pluttôt-26\",\"depth\":2,\"text\":\"Puis est arrivé iPadOS 19, ou pluttôt 26.\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20250615-ipados26.md\",\"_source\":\"content\",\"_file\":\"fr/20250615-ipados26.md\",\"_stem\":\"fr/20250615-ipados26\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20250615-ipados26\"}},\"hash\":\"jUzlWIDEXO\"}";

